프로젝트: D:\20. POC\TrmWordDict2 (Next.js 15 + Prisma 6, pnpm)
브랜치: yg_v0.2

Vitest + vitest-mock-extended 이미 설치됨. vitest.setup.ts에 prismaMock export됨.

**중요: 파일 작성 및 테스트 실행만. git commit 하지 말 것.**

## 작성할 파일들

### 1. `features/mcp/audit/log.ts`

```typescript
import { createHash } from 'crypto'
import { prisma } from '@/lib/prisma'

export type AuditInput = {
  tokenId: bigint | null
  userId: string | null
  toolName: string
  params: unknown
  status: 'success' | 'error' | 'denied'
  errorCode?: number
  latencyMs?: number
}

export async function logAudit(input: AuditInput): Promise<void> {
  try {
    const paramsHash = createHash('sha256')
      .update(JSON.stringify(input.params ?? {}))
      .digest('hex')
    await prisma.tbTrmMcpAuditLog.create({
      data: {
        tokenId: input.tokenId ?? undefined,
        userId: input.userId ?? undefined,
        toolName: input.toolName,
        paramsHash,
        status: input.status,
        errorCode: input.errorCode,
        latencyMs: input.latencyMs,
      },
    })
  } catch (e) {
    // fire-and-forget: never throw
    console.error('[mcp-audit] failed:', e)
  }
}
```

### 2. `features/mcp/audit/__tests__/log.test.ts`

```typescript
import { describe, it, expect } from 'vitest'
import { logAudit } from '../log'
import { prismaMock } from '@/vitest.setup'

describe('logAudit', () => {
  it('inserts audit record with SHA-256 params hash', async () => {
    prismaMock.tbTrmMcpAuditLog.create.mockResolvedValue({} as any)
    await logAudit({
      tokenId: 1n, userId: 'u', toolName: 'search_term',
      params: { query: '사용자' }, status: 'success', latencyMs: 45,
    })
    expect(prismaMock.tbTrmMcpAuditLog.create).toHaveBeenCalledWith({
      data: expect.objectContaining({
        tokenId: 1n,
        userId: 'u',
        toolName: 'search_term',
        paramsHash: expect.stringMatching(/^[a-f0-9]{64}$/),
        status: 'success',
        latencyMs: 45,
      }),
    })
  })

  it('does not throw when DB insert fails (fire-and-forget)', async () => {
    prismaMock.tbTrmMcpAuditLog.create.mockRejectedValue(new Error('DB down'))
    await expect(logAudit({
      tokenId: 1n, userId: 'u', toolName: 'x', params: {}, status: 'success',
    })).resolves.not.toThrow()
  })

  it('handles null tokenId/userId for unauthenticated requests', async () => {
    prismaMock.tbTrmMcpAuditLog.create.mockResolvedValue({} as any)
    await logAudit({
      tokenId: null, userId: null, toolName: '<auth-fail>',
      params: {}, status: 'denied', errorCode: -32001,
    })
    expect(prismaMock.tbTrmMcpAuditLog.create).toHaveBeenCalledWith({
      data: expect.objectContaining({
        status: 'denied',
        errorCode: -32001,
      }),
    })
  })

  it('stores different hashes for different params', async () => {
    prismaMock.tbTrmMcpAuditLog.create.mockResolvedValue({} as any)
    await logAudit({ tokenId: 1n, userId: 'u', toolName: 'a', params: { x: 1 }, status: 'success' })
    const call1 = prismaMock.tbTrmMcpAuditLog.create.mock.calls[0][0].data.paramsHash

    prismaMock.tbTrmMcpAuditLog.create.mockResolvedValue({} as any)
    await logAudit({ tokenId: 1n, userId: 'u', toolName: 'a', params: { x: 2 }, status: 'success' })
    const call2 = prismaMock.tbTrmMcpAuditLog.create.mock.calls[1][0].data.paramsHash

    expect(call1).not.toBe(call2)
  })
})
```

## 실행

```bash
pnpm test features/mcp/audit/__tests__/log.test.ts
```

